// ============= STYLES =============

const styles: Record<string, CSSProperties> = {
  // Single centered reading column; the shell has no side nav, so the
  // column cap keeps directory rows scannable on wide monitors.
  column: {
    width: '100%',
    maxWidth: 840,
    marginInline: 'auto',
    boxSizing: 'border-box',
  },
  visuallyHidden: {
    position: 'absolute',
    width: '1px',
    height: '1px',
    margin: '-1px',
    padding: 0,
    overflow: 'hidden',
    clipPath: 'inset(50%)',
    whiteSpace: 'nowrap',
  },
};

