interface OrgPerson {
  name: string;
  title: string;
  location: string;
}

interface OrgNode {
  id: string;
  name: string;
  summary: string;
  lead: string;
  location: string;
  /** Roles posted directly by this node; rollups are computed. */
  openRoles?: number;
  /** Sub-team ids — present on branch nodes. */
  childIds?: string[];
  /** Direct members — present on leaf teams. */
  people?: OrgPerson[];
}

/** One-line person fixture helper to keep the tree readable. */
